#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long u,v;
    long long w;
    bool operator<(const edge&b)const
    {
        return w<b.w;
    }
}e[3000010];
long long tot,x[100010],y[100010],lst[100010];
long long dist(long long i,long long j)
{
    return (1ll*(x[i]-x[j])*(x[i]-x[j])+1ll*(y[i]-y[j])*(y[i]-y[j]));
}
void add(long long x,long long y)
{
    e[++tot]=(edge){x,y,dist(x,y)};
}
long long fa[1000010];
long long find(long long x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(long long x,long long y)
{
    fa[find(x)]=find(y);
}
struct node
{
    long long x,y;
    bool operator<(const node&b)const
    {
        if(x==b.x)
        {
            return y<b.y;
        }
        return x<b.x;
    }
}a[1000010];
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&a[i].x,&a[i].y);
    }
    sort(a+1,a+1+n);
    for(long long i=1;i<=n;i++)
    {
        x[i]=a[i].x;
        y[i]=a[i].y;
        for(long long j=max(1ll,i-25);j<i;j++)
        {
            add(i,j);
        }
    }
    for(long long i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    long long ans=0;
    sort(e+1,e+1+tot);
    for(long long i=1;i<=tot;i++)
    {
        long long u=e[i].u,v=e[i].v,w=e[i].w;
        if(find(u)!=find(v))
        {
            merge(u,v);
            ans+=w;
        }
    }
    printf("%lld",ans);
    return 0;
}
